import unittest
from observer import Subject
class MockObserver: 
    def __init__(self): self.updated = False
    def update(self): self.updated = True
class TestObserver(unittest.TestCase):
    def test_notify(self):
        s = Subject(); o = MockObserver()
        s.attach(o); s.notify()
        self.assertTrue(o.updated)
